   275→  public shutdown(): void {
   276→    // Stop all processing intervals
   277→    for (const interval of this.processingIntervals.values()) {
   278→      clearInterval(interval);
   279→    }
   280→    this.processingIntervals.clear();
   281→
   282→    // Clear queues
